/* unused harmony import specifier */ var ipcMain;

function mainOn(name, listener) {
    external_electron_.ipcMain.on(name, (event, params) => {
        listener({ event, params });
    });
}
function mainOnce(name, listener) {
    ipcMain.once(name, (event, params) => {
        listener({ event, params });
    });
}
const mainOff = (name, listener) => {
    ipcMain.removeListener(name, listener);
};
const mainOffAll = (name) => {
    ipcMain.removeAllListeners(name);
};
function mainHandle(name, listener) {
    external_electron_.ipcMain.handle(name, async (event, params) => {
        return listener({ event, params });
    });
}
function mainHandleOnce(name, listener) {
    ipcMain.handleOnce(name, async (event, params) => {
        return listener({ event, params });
    });
}
const mainHandleRemove = (name) => {
    ipcMain.removeHandler(name);
};
function mainSend(window, name, params) {
    window.webContents.send(name, params);
}

