const userApis = [];

;// ./src/main/modules/userApi/utils.ts




let utils_userApis;
let scripts = new Map();
const saveData = () => {
    store(STORE_NAMES.USER_API).set('userApis', utils_userApis.map((api) => {
        return {
            ...api,
            script: scripts.get(api.id),
        };
    }));
};
const getUserApis = () => {
    if (utils_userApis)
        return utils_userApis;
    const electronStore_userApi = store(STORE_NAMES.USER_API);
    let infoFull = electronStore_userApi.get('userApis');
    let requiredUpdate = false;
    if (infoFull) {
        for (let i = 0; i < infoFull.length; i++) {
            const api = infoFull[i];
            if (api.version != null)
                continue;
            requiredUpdate ||= true;
            try {
                infoFull.splice(i, 1, {
                    ...parseScriptInfo(api.script),
                    ...api,
                });
            }
            catch (e) {
                infoFull.splice(i, 1);
                i--;
            }
        }
    }
    else {
        infoFull = userApis;
        electronStore_userApi.set('userApis', utils_userApis);
    }
    utils_userApis = infoFull.map((api) => {
        if (api.allowShowUpdateAlert == null)
            api.allowShowUpdateAlert = false;
        const { script, ...info } = api;
        scripts.set(api.id, script);
        return info;
    });
    if (requiredUpdate)
        saveData();
    return utils_userApis;
};
const INFO_NAMES = {
    name: 24,
    description: 36,
    author: 56,
    homepage: 1024,
    version: 36,
};
const matchInfo = (scriptInfo) => {
    const infoArr = scriptInfo.split(/\r?\n/);
    const rxp = /^\s?\*\s?@(\w+)\s(.+)$/;
    const infos = {};
    for (const info of infoArr) {
        const result = rxp.exec(info);
        if (!result)
            continue;
        const key = result[1];
        if (INFO_NAMES[key] == null)
            continue;
        infos[key] = result[2].trim();
    }
    for (const [key, len] of Object.entries(INFO_NAMES)) {
        infos[key] ||= '';
        if (infos[key] == null)
            infos[key] = '';
        else if (infos[key].length > len)
            infos[key] = infos[key].substring(0, len) + '...';
    }
    return infos;
};
const parseScriptInfo = (script) => {
    const result = /^\/\*[\S|\s]+?\*\//.exec(script);
    if (!result)
        throw new Error('无效的自定义源文件');
    let scriptInfo = matchInfo(result[0]);
    scriptInfo.name ||= `user_api_${new Date().toLocaleString()}`;
    return scriptInfo;
};
const deflateScript = async (script) => new Promise((resolve, reject) => {
    external_node_zlib_default().deflate(Buffer.from(script, 'utf8'), (err, buf) => {
        if (err) {
            reject(err);
            return;
        }
        resolve('gz_' + buf.toString('base64'));
    });
});
const inflateScript = async (script) => new Promise((resolve, reject) => {
    if (script.startsWith('gz_')) {
        external_node_zlib_default().inflate(Buffer.from(script.substring(3), 'base64'), (err, buf) => {
            if (err) {
                reject(err);
                return;
            }
            resolve(buf.toString('utf8'));
        });
    }
    else
        resolve(script);
});
const importApi = async (scriptRaw) => {
    let scriptInfo = parseScriptInfo(scriptRaw);
    const apiInfo = {
        id: `user_api_${Math.random().toString().substring(2, 5)}_${Date.now()}`,
        ...scriptInfo,
        allowShowUpdateAlert: true,
    };
    utils_userApis ??= [];
    utils_userApis.push(apiInfo);
    const script = await deflateScript(scriptRaw);
    scripts.set(apiInfo.id, script);
    saveData();
    return apiInfo;
};
const removeApi = (ids) => {
    if (!utils_userApis)
        return;
    for (let index = utils_userApis.length - 1; index > -1; index--) {
        if (ids.includes(utils_userApis[index].id)) {
            scripts.delete(utils_userApis[index].id);
            utils_userApis.splice(index, 1);
            ids.splice(index, 1);
        }
    }
    saveData();
};
const setAllowShowUpdateAlert = (id, enable) => {
    const targetApi = utils_userApis?.find((api) => api.id == id);
    if (!targetApi)
        return;
    targetApi.allowShowUpdateAlert = enable;
    saveData();
};
const getScript = async (id) => {
    return inflateScript(scripts.get(id) ?? '');
};

