const keyAuth = async (urlInfo, keyInfo) => {
    const msg = aesEncrypt(SYNC_CODE.authMsg + getComputerName(), keyInfo.key);
    return utils_request(`${urlInfo.httpProtocol}//${urlInfo.hostPath}/ah`, {
        headers: { i: keyInfo.clientId, m: msg },
    }).then(({ text, code }) => {
        if (code != 200)
            throw new Error(SYNC_CODE.authFailed);
        let msg;
        try {
            msg = aesDecrypt(text, keyInfo.key);
        }
        catch (err) {
            sync_log.error('[auth] keyAuth decryptMsg error', err.message);
            throw new Error(SYNC_CODE.authFailed);
        }
        if (msg != SYNC_CODE.helloMsg)
            return Promise.reject(new Error(SYNC_CODE.authFailed));
    });
};
const auth = async (urlInfo, serverId, authCode) => {
    if (authCode)
        return codeAuth(urlInfo, serverId, authCode);
    const keyInfo = await getSyncAuthKey(serverId);
    if (!keyInfo)
        throw new Error(SYNC_CODE.missingAuthCode);
    await keyAuth(urlInfo, keyInfo);
    return keyInfo;
};
/* harmony default export */ const client_auth = (async (urlInfo, authCode) => {
    console.log('connect: ', urlInfo.href, authCode);
    if (!(await hello(urlInfo)))
        throw new Error(SYNC_CODE.connectServiceFailed);
    const serverId = await getServerId(urlInfo);
    if (!serverId)
        throw new Error(SYNC_CODE.getServiceIdFailed);
    return auth(urlInfo, serverId, authCode);
});

