let client_status = {
    status: false,
    message: '',
    address: [],
};
const sendSyncStatus = (newStatus) => {
    client_status.status = newStatus.status;
    client_status.message = newStatus.message;
    if (client_status.status) {
        client_status.address = getAddress();
    }
    sendClientStatus(client_status);
};
const sendSyncMessage = (message) => {
    client_status.message = message;
    sendClientStatus(client_status);
};
const heartbeatTools = {
    failedNum: 0,
    maxTryNum: 100000,
    stepMs: 3000,
    connectTimeout: null,
    pingTimeout: null,
    delayRetryTimeout: null,
    handleOpen() {
        console.log('open');
        // this.failedNum = 0
        this.heartbeat();
    },
    heartbeat() {
        if (this.pingTimeout)
            clearTimeout(this.pingTimeout);
        // Use `WebSocket#terminate()`, which immediately destroys the connection,
        // instead of `WebSocket#close()`, which waits for the close timer.
        // Delay should be equal to the interval at which your server
        // sends out pings plus a conservative assumption of the latency.
        this.pingTimeout = setTimeout(() => {
            client?.terminate();
        }, 30000 + 1000);
    },
    reConnnect() {
        this.clearTimeout();
        // client = null
        if (!client)
            return;
        if (++this.failedNum > this.maxTryNum) {
            this.failedNum = 0;
            sendSyncStatus({
                status: false,
                message: 'Connect error',
            });
            throw new Error('connect error');
        }
        const waitTime = Math.min(2000 + Math.floor(this.failedNum / 2) * this.stepMs, 15000);
        // sendSyncStatus({
        //   status: false,
        //   message: `Waiting ${waitTime / 1000}s reconnnect...`,
        // })
        this.delayRetryTimeout = setTimeout(() => {
            this.delayRetryTimeout = null;
            if (!client)
                return;
            console.log(dateFormat(new Date()), 'reconnnect...');
            sendSyncStatus({
                status: false,
                message: `Try reconnnect... (${this.failedNum})`,
            });
            connect(client.data.urlInfo, client.data.keyInfo);
        }, waitTime);
    },
    clearTimeout() {
        if (this.connectTimeout) {
            clearTimeout(this.connectTimeout);
            this.connectTimeout = null;
        }
        if (this.delayRetryTimeout) {
            clearTimeout(this.delayRetryTimeout);
            this.delayRetryTimeout = null;
        }
        if (this.pingTimeout) {
            clearTimeout(this.pingTimeout);
            this.pingTimeout = null;
        }
    },
    connect(socket) {
        console.log('heartbeatTools connect');
        this.connectTimeout = setTimeout(() => {
            this.connectTimeout = null;
            if (client) {
                try {
                    client.close(SYNC_CLOSE_CODE.failed);
                }
                catch { }
            }
            if (++this.failedNum > this.maxTryNum) {
                this.failedNum = 0;
                sendSyncStatus({
                    status: false,
                    message: 'Connect error',
                });
                throw new Error('connect error');
            }
            sendSyncStatus({
                status: false,
                message: 'Connect timeout, try reconnect...',
            });
            this.reConnnect();
        }, 2 * 60 * 1000);
        socket.on('open', () => {
            if (this.connectTimeout) {
                clearTimeout(this.connectTimeout);
                this.connectTimeout = null;
            }
            this.handleOpen();
        });
        socket.on('ping', () => {
            this.heartbeat();
        });
        socket.on('close', (code) => {
            console.log(code);
            switch (code) {
                case SYNC_CLOSE_CODE.normal:
                case SYNC_CLOSE_CODE.failed:
                    return;
            }
            this.reConnnect();
        });
    },
};
let client;
// let listSyncPromise: Promise<void>
const connect = (urlInfo, keyInfo) => {
    client = new wrapper(`${urlInfo.wsProtocol}//${urlInfo.hostPath}/socket?i=${encodeURIComponent(keyInfo.clientId)}&t=${encodeURIComponent(aesEncrypt(SYNC_CODE.msgConnect, keyInfo.key))}`, {});
    client.data = {
        keyInfo,
        urlInfo,
    };
    heartbeatTools.connect(client);
    let closeEvents = [];
    let disconnected = true;
    const message2read = createMsg2call({
        funcsObj: {
            ...sync_callObj,
            finished() {
                sync_log.info('sync list success');
                client.isReady = true;
                sendSyncStatus({
                    status: true,
                    message: '',
                });
                heartbeatTools.failedNum = 0;
            },
        },
        timeout: 120 * 1000,
        sendMessage(data) {
            if (disconnected)
                throw new Error('disconnected');
            void encryptMsg(keyInfo, JSON.stringify(data))
                .then((data) => {
                client?.send(data);
            })
                .catch((err) => {
                sync_log.error('encrypt msg error: ', err);
                client?.close(SYNC_CLOSE_CODE.failed);
            });
        },
        onCallBeforeParams(rawArgs) {
            return [client, ...rawArgs];
        },
        onError(error, path, groupName) {
            const name = groupName ?? '';
            sync_log.error(`sync call ${name} ${path.join('.')} error:`, error);
            // if (groupName == null) return
            // client?.close(SYNC_CLOSE_CODE.failed)
            // sendSyncStatus({
            //   status: false,
            //   message: error.message,
            // })
        },
    });
    client.remote = message2read.remote;
    client.remoteQueueList = message2read.createQueueRemote('list');
    client.remoteQueueDislike = message2read.createQueueRemote('dislike');
    client.addEventListener('message', ({ data }) => {
        if (data == 'ping')
            return;
        if (typeof data === 'string') {
            void decryptMsg(keyInfo, data)
                .then((data) => {
                let syncData;
                try {
                    syncData = JSON.parse(data);
                }
                catch (err) {
                    sync_log.error('parse msg error: ', err);
                    client?.close(SYNC_CLOSE_CODE.failed);
                    return;
                }
                message2read.message(syncData);
            })
                .catch((error) => {
                sync_log.error('decrypt msg error: ', error);
                client?.close(SYNC_CLOSE_CODE.failed);
            });
        }
    });
    client.onClose = function (handler) {
        closeEvents.push(handler);
        return () => {
            closeEvents.splice(closeEvents.indexOf(handler), 1);
        };
    };
    const initMessage = 'Wait syncing...';
    client.addEventListener('open', () => {
        sync_log.info('connect');
        // const store = getStore()
        // global.lx.syncKeyInfo = keyInfo
        client.isReady = false;
        client.moduleReadys = {
            list: false,
            dislike: false,
        };
        disconnected = false;
        sendSyncStatus({
            status: false,
            message: initMessage,
        });
    });
    client.addEventListener('close', ({ code }) => {
        const err = new Error('closed');
        try {
            for (const handler of closeEvents)
                void handler(err);
        }
        catch (err) {
            sync_log.error(err?.message);
        }
        closeEvents = [];
        disconnected = true;
        message2read.destroy();
        switch (code) {
            case SYNC_CLOSE_CODE.normal:
                // case SYNC_CLOSE_CODE.failed:
                sendSyncStatus({
                    status: false,
                    message: '',
                });
                break;
            case SYNC_CLOSE_CODE.failed:
                if (!client_status.message || client_status.message == initMessage) {
                    sendSyncStatus({
                        status: false,
                        message: 'failed',
                    });
                }
                break;
        }
    });
    client.addEventListener('error', ({ message }) => {
        sendSyncStatus({
            status: false,
            message,
        });
    });
};
const disconnect = async () => {
    if (!client)
        return;
    sync_log.info('disconnecting...');
    client.close(SYNC_CLOSE_CODE.normal);
    client = null;
    heartbeatTools.clearTimeout();
    heartbeatTools.failedNum = 0;
};
const client_getStatus = () => client_status;

