/* harmony default export */ const migrate = (async (dataPath) => {
    const syncDataPath = external_node_path_default().join(dataPath, 'sync');
    // console.log(syncDataPath)
    if (await exists(syncDataPath))
        return;
    const oldInfoPath = external_node_path_default().join(dataPath, 'sync.json');
    // console.log(oldInfoPath)
    if (!(await exists(oldInfoPath)))
        return;
    const serverSyncDataPath = external_node_path_default().join(dataPath, File.serverDataPath);
    const clientSyncDataPath = external_node_path_default().join(dataPath, File.clientDataPath);
    await external_node_fs_default().promises.mkdir(serverSyncDataPath, { recursive: true });
    await external_node_fs_default().promises.mkdir(clientSyncDataPath, { recursive: true });
    const info = JSON.parse((await external_node_fs_default().promises.readFile(oldInfoPath)).toString());
    const serverInfoPath = external_node_path_default().join(serverSyncDataPath, File.serverInfoJSON);
    const devicesInfoPath = external_node_path_default().join(serverSyncDataPath, File.userDevicesJSON);
    const listDir = external_node_path_default().join(serverSyncDataPath, File.listDir);
    await external_node_fs_default().promises.mkdir(listDir);
    const snapshotInfo = info.snapshotInfo;
    delete info.snapshotInfo;
    snapshotInfo.clients = {};
    for (const device of Object.values(info.clients)) {
        snapshotInfo.clients[device.clientId] = {
            snapshotKey: device.snapshotKey,
            lastSyncDate: device.lastSyncDate,
        };
        device.lastConnectDate = device.lastSyncDate;
        delete device.lastSyncDate;
        delete device.snapshotKey;
    }
    const devicesInfo = {
        userName: 'default',
        clients: info.clients,
    };
    await external_node_fs_default().promises.writeFile(serverInfoPath, JSON.stringify({ serverId: info.serverId, version: 2 }));
    await external_node_fs_default().promises.writeFile(devicesInfoPath, JSON.stringify(devicesInfo));
    await external_node_fs_default().promises.writeFile(external_node_path_default().join(listDir, File.listSnapshotInfoJSON), JSON.stringify(snapshotInfo));
    const snapshotPath = external_node_path_default().join(listDir, File.listSnapshotDir);
    await external_node_fs_default().promises.mkdir(snapshotPath);
    const snapshots = (await external_node_fs_default().promises.readdir(dataPath)).filter((name) => name.startsWith('snapshot_'));
    if (snapshots.length) {
        for (const file of snapshots) {
            await external_node_fs_default().promises.copyFile(external_node_path_default().join(dataPath, file), external_node_path_default().join(snapshotPath, file));
        }
    }
    await external_node_fs_default().promises.writeFile(external_node_path_default().join(clientSyncDataPath, File.syncAuthKeysJSON), JSON.stringify(info.syncAuthKey));
    for (const file of snapshots) {
        await external_node_fs_default().promises.unlink(external_node_path_default().join(dataPath, file));
    }
    await external_node_fs_default().promises.unlink(oldInfoPath);
});

