let connectId = 0;
const handleConnect = async (host, authCode) => {
    // const hostInfo = await getSyncHost()
    // console.log(hostInfo)
    // if (!hostInfo || !hostInfo.host || !hostInfo.port) throw new Error(SYNC_CODE.unknownServiceAddress)
    const id = connectId;
    const urlInfo = parseUrl(host);
    await disconnectServer(false);
    if (id != connectId)
        return;
    const keyInfo = await client_auth(urlInfo, authCode);
    if (id != connectId)
        return;
    connect(urlInfo, keyInfo);
};
const handleDisconnect = async () => {
    await disconnect();
};
const connectServer = async (host, authCode) => {
    sendSyncStatus({
        status: false,
        message: SYNC_CODE.connecting,
    });
    const id = connectId;
    await migrate(global.lxDataPath);
    return handleConnect(host, authCode).catch(async (err) => {
        if (id != connectId)
            return;
        sendSyncStatus({
            status: false,
            message: err.message,
        });
        switch (err.message) {
            case SYNC_CODE.connectServiceFailed:
            case SYNC_CODE.missingAuthCode:
                break;
            default:
                sync_log.r_warn(err.message);
                break;
        }
        return Promise.reject(err);
    });
};
