class SnapshotDataManage {
    userDataManage;
    listDir;
    snapshotDir;
    snapshotInfoFilePath;
    snapshotInfo;
    clientSnapshotKeys;
    saveSnapshotInfoThrottle;
    isIncluedsDevice = (key) => {
        return this.clientSnapshotKeys.includes(key);
    };
    clearOldSnapshot = async () => {
        if (!this.snapshotInfo)
            return;
        const snapshotList = this.snapshotInfo.list.filter((key) => !this.isIncluedsDevice(key));
        // console.log(snapshotList.length, lx.config.maxSnapshotNum)
        const userMaxSnapshotNum = getUserConfig(this.userDataManage.userName).maxSnapshotNum;
        let requiredSave = snapshotList.length > userMaxSnapshotNum;
        while (snapshotList.length > userMaxSnapshotNum) {
            const name = snapshotList.pop();
            if (name) {
                await this.removeSnapshot(name);
                this.snapshotInfo.list.splice(this.snapshotInfo.list.indexOf(name), 1);
            }
            else
                break;
        }
        if (requiredSave)
            this.saveSnapshotInfo(this.snapshotInfo);
    };
    updateDeviceSnapshotKey = async (clientId, key) => {
        // console.log('updateDeviceSnapshotKey', key)
        let client = this.snapshotInfo.clients[clientId];
        if (!client)
            client = this.snapshotInfo.clients[clientId] = { snapshotKey: '', lastSyncDate: 0 };
        if (client.snapshotKey)
            this.clientSnapshotKeys.splice(this.clientSnapshotKeys.indexOf(client.snapshotKey), 1);
        client.snapshotKey = key;
        client.lastSyncDate = Date.now();
        this.clientSnapshotKeys.push(key);
        this.saveSnapshotInfoThrottle();
    };
    getDeviceCurrentSnapshotKey = async (clientId) => {
        // console.log('updateDeviceSnapshotKey', key)
        const client = this.snapshotInfo.clients[clientId];
        return client?.snapshotKey;
    };
    getSnapshotInfo = async () => {
        return this.snapshotInfo;
    };
    saveSnapshotInfo = (info) => {
        this.snapshotInfo = info;
        this.saveSnapshotInfoThrottle();
    };
    removeSnapshotInfo = (clientId) => {
        let client = this.snapshotInfo.clients[clientId];
        if (!client)
            return;
        if (client.snapshotKey)
            this.clientSnapshotKeys.splice(this.clientSnapshotKeys.indexOf(client.snapshotKey), 1);
        delete this.snapshotInfo.clients[clientId];
        this.saveSnapshotInfoThrottle();
    };
    getSnapshot = async (name) => {
        const filePath = external_node_path_default().join(this.snapshotDir, `snapshot_${name}`);
        let listData;
        try {
            listData = JSON.parse((await external_node_fs_default().promises.readFile(filePath)).toString('utf-8'));
        }
        catch (err) {
            sync_log.warn(err);
            return null;
        }
        return listData;
    };
    saveSnapshot = async (name, data) => {
        sync_log.info('saveSnapshot', this.userDataManage.userName, name);
        const filePath = external_node_path_default().join(this.snapshotDir, `snapshot_${name}`);
        try {
            await external_node_fs_default().promises.writeFile(filePath, data);
        }
        catch (err) {
            sync_log.error(err);
            throw err;
        }
    };
    removeSnapshot = async (name) => {
        sync_log.info('removeSnapshot', this.userDataManage.userName, name);
        const filePath = external_node_path_default().join(this.snapshotDir, `snapshot_${name}`);
        try {
            await external_node_fs_default().promises.unlink(filePath);
        }
        catch (err) {
            sync_log.error(err);
        }
    };
    constructor(userDataManage) {
        this.userDataManage = userDataManage;
        this.listDir = external_node_path_default().join(userDataManage.userDir, File.listDir);
        checkAndCreateDirSync(this.listDir);
        this.snapshotDir = external_node_path_default().join(this.listDir, File.listSnapshotDir);
        checkAndCreateDirSync(this.snapshotDir);
        this.snapshotInfoFilePath = external_node_path_default().join(this.listDir, File.listSnapshotInfoJSON);
        this.snapshotInfo = external_node_fs_default().existsSync(this.snapshotInfoFilePath)
            ? JSON.parse(external_node_fs_default().readFileSync(this.snapshotInfoFilePath).toString())
            : { latest: null, time: 0, list: [], clients: {} };
        this.saveSnapshotInfoThrottle = throttle(() => {
            external_node_fs_default().writeFile(this.snapshotInfoFilePath, JSON.stringify(this.snapshotInfo), 'utf8', (err) => {
                if (err)
                    console.error(err);
                void this.clearOldSnapshot();
            });
        });
        this.clientSnapshotKeys = Object.values(this.snapshotInfo.clients)
            .map((device) => device.snapshotKey)
            .filter((k) => k);
    }
}
