const dislike_sync_handler_handler = {
    async onDislikeSyncAction(socket, action) {
        if (!socket.moduleReadys.dislike)
            return;
        await handleRemoteDislikeAction(action);
        const userSpace = getUserSpace(socket.userInfo.name);
        const key = await userSpace.dislikeManage.createSnapshot();
        userSpace.dislikeManage.updateDeviceSnapshotKey(socket.keyInfo.clientId, key);
        const currentUserName = socket.userInfo.name;
        const currentId = socket.keyInfo.clientId;
        socket.broadcast((client) => {
            if (client.keyInfo.clientId == currentId ||
                !client.moduleReadys?.dislike ||
                client.userInfo.name != currentUserName)
                return;
            void client.remoteQueueDislike
                .onDislikeSyncAction(action)
                .then(async () => {
                return userSpace.dislikeManage.updateDeviceSnapshotKey(client.keyInfo.clientId, key);
            })
                .catch((err) => {
                // TODO send status
                client.close(SYNC_CLOSE_CODE.failed);
                // client.moduleReadys.dislike = false
                console.log(err.message);
            });
        });
    },
};
/* harmony default export */ const dislike_sync_handler = (dislike_sync_handler_handler);

;// ./src/main/modules/sync/server/modules/dislike/utils.ts

const filterRules = (rules) => {
    const list = [];
    for (const item of rules.split('\n')) {
        if (!item)
            continue;
        let [name, singer] = item.split(SPLIT_CHAR.DISLIKE_NAME);
        if (name) {
            name = name
                .replaceAll(SPLIT_CHAR.DISLIKE_NAME, SPLIT_CHAR.DISLIKE_NAME_ALIAS)
                .toLocaleLowerCase()
                .trim();
            if (singer) {
                singer = singer
                    .replaceAll(SPLIT_CHAR.DISLIKE_NAME, SPLIT_CHAR.DISLIKE_NAME_ALIAS)
                    .toLocaleLowerCase()
                    .trim();
                list.push(`${name}${SPLIT_CHAR.DISLIKE_NAME}${singer}`);
            }
            else {
                list.push(name);
            }
        }
        else if (singer) {
            singer = singer
                .replaceAll(SPLIT_CHAR.DISLIKE_NAME, SPLIT_CHAR.DISLIKE_NAME_ALIAS)
                .toLocaleLowerCase()
                .trim();
            list.push(`${SPLIT_CHAR.DISLIKE_NAME}${singer}`);
        }
    }
    return new Set(list);
};

