const server_sync_handler_handler = {
    async onFeatureChanged(socket, feature) {
        // const userSpace = getUserSpace(socket.userInfo.name)
        const beforeFeature = socket.feature;
        for (const name of FeaturesList) {
            const newStatus = feature[name];
            if (newStatus == null)
                continue;
            beforeFeature[name] = feature[name];
            socket.moduleReadys[name] = false;
            if (feature[name])
                await server_modules_modules[name].sync(socket).catch((_) => _);
        }
    },
};
/* harmony default export */ const server_sync_handler = (server_sync_handler_handler);

;// ./src/main/modules/sync/server/server/sync/sync.ts


const sync_sync_sync = async (socket) => {
    let disconnected = false;
    socket.onClose(() => {
        disconnected = true;
    });
    const enabledFeatures = await socket.remote.getEnabledFeatures('desktop-app', modules_featureVersion);
    if (disconnected)
        throw new Error('disconnected');
    for (const moduleName of FeaturesList) {
        if (enabledFeatures[moduleName]) {
            socket.feature[moduleName] = enabledFeatures[moduleName];
            await server_modules_modules[moduleName].sync(socket).catch((_) => _);
        }
        if (disconnected)
            throw new Error('disconnected');
    }
    await socket.remote.finished();
};

