let selectModeListenr = null;
/* harmony default export */ const rendererEvent_sync = (() => {
    mainHandle(WIN_MAIN_RENDERER_EVENT_NAME.sync_action, async ({ params: data }) => {
        switch (data.action) {
            case 'enable_server':
                data.data.enable ? await startServer(parseInt(data.data.port)) : await stopServer();
                return;
            case 'enable_client':
                data.data.enable
                    ? await connectServer(data.data.host, data.data.authCode)
                    : await disconnectServer();
                return;
            case 'get_server_status':
                return server_getStatus();
            case 'get_client_status':
                return client_getStatus();
            case 'generate_code':
                return server_generateCode();
            case 'select_mode':
                if (selectModeListenr) {
                    selectModeListenr(data.data.mode);
                    selectModeListenr = null;
                }
                break;
            default:
                break;
        }
    });
    mainHandle(WIN_MAIN_RENDERER_EVENT_NAME.sync_get_server_devices, async () => {
        return getDevices();
    });
    mainHandle(WIN_MAIN_RENDERER_EVENT_NAME.sync_remove_server_device, async ({ params: clientId }) => {
        await removeDevice(clientId);
    });
});
const sendSyncAction = (data) => {
    sendEvent(WIN_MAIN_RENDERER_EVENT_NAME.sync_action, data);
};
const sendClientStatus = (status) => {
    sendSyncAction({
        action: 'client_status',
        data: status,
    });
};
const sendServerStatus = (status) => {
    sendSyncAction({
        action: 'server_status',
        data: status,
    });
};
const sendSelectMode = (deviceName, type, listener) => {
    selectModeListenr = listener;
    sendSyncAction({ action: 'select_mode', data: { deviceName, type } });
};
const removeSelectModeListener = () => {
    if (selectModeListenr)
        selectModeListenr(null);
    selectModeListenr = null;
};
const sendCloseSelectMode = () => {
    sendSyncAction({ action: 'close_select_mode' });
};

