;// ./src/main/modules/openApi/index.ts




const sendResponse = (res, code = 200, msg = 'OK', contentType = 'text/plain; charset=utf-8') => {
    res.writeHead(code, {
        'Content-Type': contentType,
        'Access-Control-Allow-Origin': '*',
    });
    if (typeof msg === 'object') {
        res.end(JSON.stringify(msg));
    }
    else {
        res.end(msg);
    }
};
let openApi_status = {
    status: false,
    message: '',
    address: '',
};
let openApi_httpServer;
let openApi_sockets = new Set();
let responses = new Map();
let playerStatusKeys;
const defaultFilter = [
    'status',
    'name',
    'singer',
    'albumName',
    'lyricLineText',
    'duration',
    'progress',
    'playbackRate',
];
const parseFilter = (filter) => {
    if (typeof filter != 'string')
        return defaultFilter;
    filter = filter.split(',');
    const subKeys = playerStatusKeys.filter((k) => filter.includes(k));
    return subKeys.length ? subKeys : defaultFilter;
};
const handleSendStatus = (res, query) => {
    const keys = parseFilter(external_node_querystring_default().parse(query ?? '').filter);
    const resp = {};
    for (const k of keys)
        resp[k] = global.lx.player_status[k];
    sendResponse(res, 200, resp, 'application/json; charset=utf-8');
};
const handleSendAllLyric = (res) => {
    const resp = {
        lyric: global.lx.player_status.lyric,
        tlyric: global.lx.player_status.tlyric,
        rlyric: global.lx.player_status.rlyric,
        lxlyric: global.lx.player_status.lxlyric,
    };
    sendResponse(res, 200, resp, 'application/json; charset=utf-8');
};
const handleSubscribePlayerStatus = (req, res, query) => {
    res.writeHead(200, {
        'Content-Type': 'text/event-stream',
        Connection: 'keep-alive',
        'Cache-Control': 'no-cache',
        'Access-Control-Allow-Origin': '*',
    });
    req.socket.setTimeout(0);
    req.on('close', () => {
        res.end('OK');
        responses.delete(res);
    });
    const keys = parseFilter(external_node_querystring_default().parse(query ?? '').filter);
    responses.set(res, keys);
    for (const [k, v] of Object.entries(global.lx.player_status)) {
        if (!keys.includes(k))
            continue;
        res.write(`event: ${k}\n`);
        res.write(`data: ${JSON.stringify(v)}\n\n`);
    }
};
const openApi_handleStartServer = async (port, ip) => new Promise((resolve, reject) => {
    playerStatusKeys = Object.keys(global.lx.player_status);
    openApi_httpServer = external_node_http_default().createServer((req, res) => {
        const [endUrl, query] = `/${req.url?.split('/').at(-1) ?? ''}`.split('?');
        let code = 200;
        let msg = 'OK';
        switch (endUrl) {
            case '/status':
                handleSendStatus(res, query);
                return;
            // case '/test':
            //   code = 200
            //   res.setHeader('Content-Type', 'text/html; charset=utf-8')
            //   msg = `<!DOCTYPE html>
            //   <html lang="en">
            //     <head>
            //       <meta charset="UTF-8" />
            //       <meta http-equiv="X-UA-Compatible" content="IE=edge" />
            //       <meta name="viewport" content="width=device-width, initial-scale=1.0" />
            //       <title>Nodejs Server-Sent Events</title>
            //     </head>
            //     <body>
            //       <h1>Hello SSE!</h1>
            //       <h2>List of Server-sent events</h2>
            //       <ul id="sse-list"></ul>
            //       <script>
            //         const subscription = new EventSource('/subscribe-player-status');
            //       // Default events
            //       subscription.addEventListener('open', () => {
            //           console.log('Connection opened')
            //       });
            //       subscription.addEventListener('error', (err) => {
            //           console.error(err)
            //       });
            //       subscription.addEventListener('lyricLineText', (event) => {
            //           console.log(event.data)
            //       });
            //       subscription.addEventListener('progress', (event) => {
            //           console.log(event.data)
            //       });
            //       subscription.addEventListener('name', (event) => {
            //           console.log(event.data)
            //       });
            //       subscription.addEventListener('singer', (event) => {
            //           console.log(event.data)
            //       });
            //       </script>
            //     </body>
            //   </html>`
            //   break
            case '/lyric':
                msg = global.lx.player_status.lyric;
                break;
            case '/lyric-all':
                handleSendAllLyric(res);
                return;
            case '/play':
                sendTaskbarButtonClick('play');
                break;
            case '/pause':
                sendTaskbarButtonClick('pause');
                break;
            case '/skip-next':
                sendTaskbarButtonClick('next');
                break;
            case '/skip-prev':
                sendTaskbarButtonClick('prev');
                break;
            case '/seek': {
                const offset = parseFloat(external_node_querystring_default().parse(query ?? '').offset);
                if (Number.isNaN(offset) || offset < 0 || offset > global.lx.player_status.duration) {
                    code = 400;
                    msg = 'Invalid offset';
                }
                else {
                    sendTaskbarButtonClick('seek', parseFloat(offset.toFixed(3)));
                }
                break;
            }
            case '/collect':
                sendTaskbarButtonClick('collect');
                break;
            case '/uncollect':
                sendTaskbarButtonClick('unCollect');
                break;
            case '/volume': {
                const volume = parseInt(external_node_querystring_default().parse(query ?? '').volume);
                if (Number.isNaN(volume) || volume < 0 || volume > 100) {
                    code = 400;
                    msg = 'Invalid volume';
                }
                else {
                    sendTaskbarButtonClick('volume', volume / 100);
                }
                break;
            }
            case '/mute': {
                const mute = external_node_querystring_default().parse(query ?? '').mute;
                if (mute == 'true') {
                    sendTaskbarButtonClick('mute', true);
                }
                else if (mute == 'false') {
                    sendTaskbarButtonClick('mute', false);
                }
                else {
                    code = 400;
                    msg = 'Invalid mute value';
                }
                break;
            }
            case '/subscribe-player-status':
                try {
                    handleSubscribePlayerStatus(req, res, query);
                    return;
                }
                catch (err) {
                    console.log(err);
                    code = 500;
                    msg = 'Error';
                }
                break;
            default:
                code = 401;
                msg = 'Forbidden';
                break;
        }
        sendResponse(res, code, msg);
    });
    openApi_httpServer.on('error', (error) => {
        console.log(error);
        reject(error);
    });
    openApi_httpServer.on('connection', (socket) => {
        openApi_sockets.add(socket);
        socket.once('close', () => {
            openApi_sockets.delete(socket);
        });
        socket.setTimeout(4000);
    });
    openApi_httpServer.on('listening', () => {
        const addr = openApi_httpServer.address();
        // console.log(addr)
        if (!addr) {
            reject(new Error('address is null'));
            return;
        }
        resolve();
    });
    openApi_httpServer.listen(port, ip);
});
const openApi_handleStopServer = async () => new Promise((resolve, reject) => {
    if (!openApi_httpServer)
        return;
    openApi_httpServer.close((err) => {
        if (err) {
            reject(err);
            return;
        }
        resolve();
    });
    for (const socket of openApi_sockets)
        socket.destroy();
    openApi_sockets.clear();
    responses.clear();
});
const openApi_sendStatus = (status) => {
    if (!responses.size)
        return;
    for (const [resp, keys] of responses) {
        for (const [k, v] of Object.entries(status)) {
            if (!keys.includes(k))
                continue;
            resp.write(`event: ${k}\n`);
            resp.write(`data: ${JSON.stringify(v)}\n\n`);
        }
    }
};
const openApi_stopServer = async () => {
    global.lx.event_app.off('player_status', openApi_sendStatus);
    if (!openApi_status.status) {
        openApi_status.status = false;
        openApi_status.message = '';
        openApi_status.address = '';
        return openApi_status;
    }
    await openApi_handleStopServer()
        .then(() => {
        openApi_status.status = false;
        openApi_status.message = '';
        openApi_status.address = '';
    })
        .catch((err) => {
        console.log(err);
        openApi_status.message = err.message;
    });
    return openApi_status;
};
const openApi_startServer = async (port, bindLan) => {
    if (openApi_status.status)
        await openApi_stopServer();
    await openApi_handleStartServer(port, bindLan ? '0.0.0.0' : '127.0.0.1')
        .then(() => {
        openApi_status.status = true;
        openApi_status.message = '';
        let address = ['127.0.0.1'];
        if (bindLan)
            address = [...address, ...getAddress()];
        openApi_status.address = address.join(', ');
    })
        .catch((err) => {
        console.log(err);
        openApi_status.status = false;
        openApi_status.message = err.message;
        openApi_status.address = '';
    });
    global.lx.event_app.on('player_status', openApi_sendStatus);
    return openApi_status;
};
const openApi_getStatus = () => openApi_status;

;// ./src/main/modules/winMain/rendererEvent/openAPI.ts



/* harmony default export */ const openAPI = (() => {
    mainHandle(WIN_MAIN_RENDERER_EVENT_NAME.open_api_action, async ({ params: data }) => {
        switch (data.action) {
            case 'enable':
                return data.data.enable
                    ? await openApi_startServer(parseInt(data.data.port), data.data.bindLan)
                    : await openApi_stopServer();
            case 'status':
                return openApi_getStatus();
        }
    });
});

